// Load answer bank files from disk
const fs = require('fs');
const path = require('path');

const BANK_ROOT = 'C:/Users/joie.sayen/Claude Code/security-questionnaire-bank';

function readMarkdownFiles(dir) {
  const results = [];
  try {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        results.push(...readMarkdownFiles(fullPath));
      } else if (entry.name.endsWith('.md') && entry.name !== 'README.md') {
        try {
          const content = fs.readFileSync(fullPath, 'utf-8');
          results.push({
            file: fullPath.replace(BANK_ROOT + '/', '').replace(BANK_ROOT + '\\', ''),
            content: content
          });
        } catch (e) {
          // skip unreadable files
        }
      }
    }
  } catch (e) {
    // skip unreadable dirs
  }
  return results;
}

// Read categories (org-wide answers)
const categories = readMarkdownFiles(path.join(BANK_ROOT, 'categories'));

// Read policies
const policies = readMarkdownFiles(path.join(BANK_ROOT, 'policies'));

// Read product profiles and overrides
const products = readMarkdownFiles(path.join(BANK_ROOT, 'products'));

// Read glossary
let glossary = '';
try {
  glossary = fs.readFileSync(path.join(BANK_ROOT, 'glossary.md'), 'utf-8');
} catch (e) {}

// Build the knowledge base context string
const knowledgeBase = [
  '=== CATEGORY ANSWERS (Organization-wide) ===',
  ...categories.map(f => `\n--- ${f.file} ---\n${f.content}`),
  '\n=== POLICIES ===',
  ...policies.map(f => `\n--- ${f.file} ---\n${f.content}`),
  '\n=== PRODUCT DETAILS & OVERRIDES ===',
  ...products.map(f => `\n--- ${f.file} ---\n${f.content}`),
  '\n=== GLOSSARY ===',
  glossary
].join('\n');

// Get all questionnaire items from previous node
const items = $input.all();

// Batch questions into groups of 10 for efficient API calls
const batchSize = 10;
const batches = [];

for (let i = 0; i < items.length; i += batchSize) {
  const batch = items.slice(i, i + batchSize);
  const questions = batch.map((item, idx) => {
    // Try to find the question column - common column names
    const json = item.json;
    const questionCol = Object.keys(json).find(k => 
      /question|query|requirement|control|item|description/i.test(k)
    ) || Object.keys(json)[1] || Object.keys(json)[0];

    const idCol = Object.keys(json).find(k => 
      /id|number|#|ref|index/i.test(k)
    ) || Object.keys(json)[0];

    return {
      index: i + idx,
      id: json[idCol] || `Q${i + idx + 1}`,
      question: json[questionCol] || '',
      originalData: json
    };
  });

  batches.push({
    json: {
      batchIndex: Math.floor(i / batchSize),
      questions: questions,
      knowledgeBase: knowledgeBase,
      totalQuestions: items.length
    }
  });
}

return batches;

