// Parse Claude API responses and merge with original data
const items = $input.all();
const allAnswered = [];

for (const item of items) {
  try {
    const response = item.json;

    // Extract text content from Claude response
    let text = '';
    if (response.content && Array.isArray(response.content)) {
      text = response.content.map(c => c.text || '').join('');
    } else if (typeof response.body === 'string') {
      text = response.body;
    } else if (response.data) {
      text = JSON.stringify(response.data);
    }

    // Parse JSON from response
    const jsonMatch = text.match(/\[\s*\{[\s\S]*\}\s*\]/);
    if (jsonMatch) {
      const answers = JSON.parse(jsonMatch[0]);
      for (const ans of answers) {
        allAnswered.push({
          json: {
            'Question ID': ans.id || '',
            'Question': ans.question || '',
            'Answer': ans.answer || '',
            'Source': ans.source || '',
            'Confidence': ans.confidence || 'low',
            'Needs Review': ans.confidence === 'low' ? 'YES' : 'NO'
          }
        });
      }
    }
  } catch (e) {
    allAnswered.push({
      json: {
        'Question ID': 'ERROR',
        'Question': 'Failed to parse batch',
        'Answer': e.message,
        'Source': 'error',
        'Confidence': 'none',
        'Needs Review': 'YES'
      }
    });
  }
}

if (allAnswered.length === 0) {
  return [{ json: { error: 'No answers generated. Check Claude API response.' } }];
}

return allAnswered;
